// DLQ Entry Creation and Error Categorization
const input = $input.first().json;

// Determine if triggered by error or manual webhook
const isErrorTrigger = input.execution?.error !== undefined;

// Extract error context
function extractErrorContext(input) {
  if (isErrorTrigger) {
    return {
      executionId: input.execution?.id || $execution.id,
      errorMessage: input.execution?.error?.message || 'Unknown error',
      errorStack: input.execution?.error?.stack,
      failedNode: input.execution?.lastNodeExecuted || 'Unknown',
      originalPayload: input.execution?.data || input,
      httpStatusCode: input.execution?.error?.response?.statusCode
    };
  } else {
    // Manual webhook invocation
    return {
      executionId: input.executionId || $execution.id,
      errorMessage: input.errorMessage || input.message || 'Manual DLQ entry',
      errorStack: input.errorStack,
      failedNode: input.failedNode || 'Manual',
      originalPayload: input.payload || input,
      httpStatusCode: input.httpStatusCode
    };
  }
}

// Categorize error based on message and status code
function categorizeError(errorMsg, statusCode) {
  const msg = (errorMsg || '').toLowerCase();
  const code = parseInt(statusCode) || 0;

  // Rate limit detection
  if (code === 429 || msg.includes('rate limit') || msg.includes('too many requests')) {
    return 'RATE_LIMIT';
  }

  // Authentication failures
  if (code === 401 || code === 403 || msg.includes('unauthorized') || msg.includes('forbidden') || msg.includes('auth')) {
    return 'AUTHENTICATION';
  }

  // Validation errors
  if (code === 400 || code === 422 || msg.includes('validation') || msg.includes('invalid') || msg.includes('required field')) {
    return 'VALIDATION';
  }

  // Not found - permanent
  if (code === 404 || msg.includes('not found')) {
    return 'PERMANENT';
  }

  // Service unavailable - dependency
  if (code === 503 || code === 502 || code === 504 || msg.includes('unavailable') || msg.includes('service down')) {
    return 'DEPENDENCY';
  }

  // Network errors
  if (msg.includes('timeout') || msg.includes('econnreset') || msg.includes('etimedout') || msg.includes('enotfound') || msg.includes('connection')) {
    return 'NETWORK';
  }

  // Transient errors
  if (msg.includes('temporary') || msg.includes('retry') || msg.includes('busy') || code === 429) {
    return 'TRANSIENT';
  }

  return 'UNKNOWN';
}

// Calculate next retry with exponential backoff
function calculateNextRetry(retryCount, category) {
  const baseDelay = category === 'RATE_LIMIT' ? 10 : 5; // minutes
  const maxDelay = 120; // 2 hours cap
  const multiplier = Math.pow(2, retryCount);
  const jitter = Math.floor(Math.random() * 60) - 30; // ±30 seconds

  const delayMinutes = Math.min(baseDelay * multiplier, maxDelay);
  const nextRetry = new Date(Date.now() + (delayMinutes * 60 + jitter) * 1000);

  return {
    delayMinutes,
    nextRetryAt: nextRetry.toISOString()
  };
}

// Determine initial status based on category
function determineInitialStatus(category, retryCount) {
  const immediatePoisonCategories = ['VALIDATION', 'PERMANENT'];
  if (immediatePoisonCategories.includes(category)) {
    return 'PERMANENT_FAILURE';
  }
  if (retryCount >= 5) {
    return 'PERMANENT_FAILURE';
  }
  return 'PENDING_RETRY';
}

// Extract form type from payload
function extractFormType(payload) {
  const body = payload?.body || payload?.data || payload;
  return body?.formType || body?.form_type || 'consultation';
}

// Extract source info
function extractSourceInfo(payload) {
  const headers = payload?.headers || {};
  return {
    sourceIp: headers['x-forwarded-for'] || headers['x-real-ip'] || null,
    userAgent: headers['user-agent'] || null
  };
}

const errorCtx = extractErrorContext(input);
const category = categorizeError(errorCtx.errorMessage, errorCtx.httpStatusCode);
const retryCount = input.retryCount || 0;
const retryInfo = calculateNextRetry(retryCount, category);
const status = determineInitialStatus(category, retryCount);
const sourceInfo = extractSourceInfo(errorCtx.originalPayload);
const formType = extractFormType(errorCtx.originalPayload);

// Build DLQ entry
const dlqEntry = {
  execution_id: errorCtx.executionId,
  original_payload: errorCtx.originalPayload,
  error_message: errorCtx.errorMessage.substring(0, 1000), // Limit length
  error_stack: errorCtx.errorStack?.substring(0, 2000),
  error_category: category,
  failed_node: errorCtx.failedNode,
  http_status_code: errorCtx.httpStatusCode,
  status: status,
  retry_count: retryCount,
  max_retries: 5,
  next_retry_at: status === 'PENDING_RETRY' ? retryInfo.nextRetryAt : null,
  source_ip: sourceInfo.sourceIp,
  user_agent: sourceInfo.userAgent,
  form_type: formType,
  workflow_version: '1.0.0',
  environment: $env.ENVIRONMENT || 'production',
  n8n_instance_id: $env.N8N_INSTANCE_ID || 'default',
  retry_history: [{
    attempt_number: 0,
    attempted_at: new Date().toISOString(),
    result: 'failed',
    error: errorCtx.errorMessage,
    node: errorCtx.failedNode
  }]
};

return [{ json: dlqEntry }];

// Format data for Google Sheets backup
const dlq = $input.first().json;
const payload = dlq.original_payload?.body || dlq.original_payload?.data || dlq.original_payload || {};
const data = payload.data || payload;

// Format timestamp for readability
const formatTime = (iso) => {
  if (!iso) return 'N/A';
  try {
    return new Date(iso).toLocaleString('en-US', {
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  } catch {
    return iso;
  }
};

// Truncate long messages
const truncate = (str, len) => {
  if (!str) return 'N/A';
  return str.length > len ? str.substring(0, len) + '...' : str;
};

return [{
  json: {
    Timestamp: new Date().toISOString(),
    Execution_ID: truncate(dlq.execution_id, 20),
    Email: data.email || data.Email || 'N/A',
    Company: data.company || data.Company || data.organization || 'N/A',
    Name: data.name || (data.firstName && data.lastName ? `${data.firstName} ${data.lastName}` : 'N/A'),
    Error_Category: dlq.error_category,
    Error_Message: truncate(dlq.error_message, 150),
    Failed_Node: dlq.failed_node || 'N/A',
    Retry_Count: `${dlq.retry_count}/${dlq.max_retries}`,
    Status: dlq.status,
    Next_Retry: formatTime(dlq.next_retry_at),
    Form_Type: dlq.form_type
  }
}];

